   411→            entry_type: match entry.entry_type {
   412→                EntryType::File => PD_FTYPE_FILE,
   413→                EntryType::Directory => PD_FTYPE_DIR,
   414→            },
   415→            size: entry.size,
   416→        };
   417→        let mut name = [0u8; 13];
   418→        let len = format_app_name(&entry.name, &mut name);
   419→        dirent.name[..len].copy_from_slice(&name[..len]);
