   422→    #[panic_handler]
   423→    fn panic(info: &core::panic::PanicInfo<'_>) -> ! {
   424→        // Emit a deterministic crash report via USB Serial/JTAG so the panic
   425→        // location is visible on the host instead of the device freezing silently.
   426→        serial_write_bytes(b"\r\n!!! PANIC !!!\r\n");
   427→        if let Some(loc) = info.location() {
   428→            // Format "file:line\r\n" into a small stack buffer; no heap needed.
   429→            let mut buf = [0u8; 128];
   430→            let mut cursor = &mut buf[..];
   431→            let _ = write!(cursor, "{}:{}\r\n", loc.file(), loc.line());
   432→            let written = 128 - cursor.len();
   433→            serial_write_bytes(&buf[..written]);
   434→        }
   435→        loop {
   436→            spin_loop();
   437→        }
   438→    }
