   465→                        render_boot_placeholder(launcher_buf, BootFailureKind::None);
   466→                        device_refresh_frame(launcher_buf);
   467→                        loop {
   468→                            spin_loop();
   469→                        }
   470→                    }
   471→
   472→                    if let Ok(event) = (&mut *INPUT_PTR).poll() {
   473→                        if let Some(event) = event {
   474→                            last_event = Some(event);
   475→                        }
   476→                    }
   477→
   478→                    let (gpio1_mv, gpio2_mv) = (&*INPUT_PTR).last_samples();
   479→                    let (gpio1_decoded, gpio2_decoded) = (&*INPUT_PTR).last_decoded();
   480→                    let snapshot = ButtonDiagSnapshot {
   481→                        gpio1_mv,
   482→                        gpio2_mv,
   483→                        gpio1_decoded,
   484→                        gpio2_decoded,
   485→                        stable: (&*INPUT_PTR).current_button(),
   486→                        last_event,
   487→                    };
   488→
   489→                    if snapshot != last_snapshot {
   490→                        render_button_diagnostics(launcher_buf, &snapshot);
   491→                        device_refresh_frame(launcher_buf);
   492→                        last_snapshot = snapshot;
   493→                    }
   494→
   495→                    Delay::new().delay_millis(20);
   496→                }
   497→            }
   498→
   499→            if FS_PTR.is_null() || APP_REGION_PTR.is_null() || PDB_BUF_PTR.is_null() {
   500→                render_boot_placeholder(launcher_buf, BOOT_FAILURE);
   501→                device_refresh_frame(launcher_buf);
   502→                loop {
   503→                    spin_loop();
   504→                }
   505→            }
   506→
   507→            let fs = &mut *FS_PTR;
   508→            let app_region = &mut (&mut *APP_REGION_PTR)[..];
   509→            let pdb_buf = &mut (&mut *PDB_BUF_PTR)[..];
   510→
   511→            loop {
   512→                let filename = run_launcher_with_refresh(fs, launcher_buf, device_refresh_frame);
   513→                let syscalls = build_syscall_table(app_region.as_ptr() as u32, app_region.len() as u32);
   514→                let _ = load_and_run(fs, &filename, pdb_buf, app_region, &syscalls, jump_to_app);
   515→            }
   516→        }
   517→    }
   518→
   519→    #[main]
   520→    fn main() -> ! {
   521→        let config = Config::default().with_cpu_clock(CpuClock::max());
   522→        let peripherals = esp_hal::init(config);
   523→
   524→        // ── G1: USB Serial/JTAG console — must come first so panics can emit ──
   525→        let serial = SERIAL_CELL.init(UsbSerialJtag::new(peripherals.USB_DEVICE));
   526→        // SAFETY: written once before any task or panic handler runs; single-core.
   527→        unsafe {
   528→            SERIAL_PTR = serial as *mut _;
   529→            set_serial_write_fn(device_serial_write);
   530→        }
   531→        serial_write_bytes(b"\r\nPaperDOS kernel boot\r\n");
   532→
   533→        let adc1 = unsafe { peripherals.ADC1.clone_unchecked() };
   534→        let gpio1 = unsafe { peripherals.GPIO1.clone_unchecked() };
   535→        let gpio2 = unsafe { peripherals.GPIO2.clone_unchecked() };
   536→
   537→        let tx_buf = DmaTxBuf::new(
   538→            TX_DESC.init([DmaDescriptor::EMPTY; 2]),
   539→            TX_BUF.init([0u8; 4096]),
   540→        )
   541→        .unwrap();
   542→        let rx_buf = DmaRxBuf::new(
   543→            RX_DESC.init([DmaDescriptor::EMPTY; 2]),
   544→            RX_BUF.init([0u8; 4096]),
   545→        )
   546→        .unwrap();
   547→
   548→        let mut spi_raw = spi::master::Spi::new(
   549→            peripherals.SPI2,
   550→            SpiConfig::default()
   551→                .with_frequency(Rate::from_khz(400))
   552→                .with_mode(Mode::_0),
   553→        )
   554→        .unwrap()
   555→        .with_sck(peripherals.GPIO8)
   556→        .with_mosi(peripherals.GPIO10)
   557→        .with_miso(peripherals.GPIO7);
   558→        let _ = spi_raw.write(&[0xFF; 10]);
   559→        let spi_bus = spi_raw
   560→            .with_dma(peripherals.DMA_CH0)
   561→            .with_buffers(rx_buf, tx_buf);
   562→        let spi_ref = SPI_BUS_CELL.init(Mutex::new(RefCell::new(spi_bus)));
   563→
   564→        let fs = if BUTTON_DIAGNOSTIC_MODE {
   565→            Err(BootFailureKind::None)
   566→        } else {
   567→            let sd_spi: SdSpiDevice<'static, Delay> = CriticalSectionDevice::new(
   568→                spi_ref,
   569→                DummyCsPin,
   570→                Delay::new(),
   571→            )
   572→            .unwrap();
   573→            DeviceFs::from_spi2(
   574→                sd_spi,
   575→                // SAFETY: GPIO12 is free for SD CS on the X4 in DIO flash mode.
   576→                unsafe { RawOutputPin::new(12) },
   577→                Delay::new(),
   578→            )
   579→            .map_err(|err| map_boot_failure("sd_init", err))
   580→        };
   581→
   582→        let display_spi = CriticalSectionDevice::new(
   583→            spi_ref,
   584→            Output::new(peripherals.GPIO21, Level::High, OutputConfig::default()),
   585→            Delay::new(),
   586→        )
   587→        .unwrap();
   588→        let mut display = X4DisplayTransport::new(
   589→            display_spi,
   590→            peripherals.GPIO4,
   591→            peripherals.GPIO5,
   592→            peripherals.GPIO6,
   593→        );
   594→        emit_reset_preamble(&mut display).unwrap();
   595→        emit_power_init_block(&mut display).unwrap();
   596→        emit_addressing_init_block(&mut display).unwrap();
   597→
   598→        // F8: Store the transport and wire all device globals before spawning tasks.
   599→        let transport_ref = TRANSPORT_CELL.init(display);
   600→        let launcher_buf_ref = LAUNCHER_BUF_CELL.init([0xFF; FRAME_BYTES]);
   601→        let app_region_ref = APP_REGION_CELL.init([0u8; APP_REGION_BYTES]);
   602→        let pdb_buf_ref = PDB_BUF_CELL.init([0u8; PDB_BUF_BYTES]);
   603→        let fs_ref = match fs {
   604→            Ok(fs) => FS_CELL.init(fs) as *mut _,
   605→            Err(failure) => {
   606→                unsafe { BOOT_FAILURE = failure; }
   607→                core::ptr::null_mut()
   608→            }
   609→        };
   610→        // SAFETY: written once here before the executor starts; single-core.
   611→        unsafe {
   612→            TRANSPORT_PTR = transport_ref as *mut _;
   613→            FS_PTR = fs_ref;
   614→            LAUNCHER_BUF_PTR = launcher_buf_ref as *mut _;
   615→            APP_REGION_PTR = app_region_ref as *mut _;
   616→            PDB_BUF_PTR = pdb_buf_ref as *mut _;
