   631→        unsafe {
   632→            set_display_flush_fn(device_display_flush);
   633→            set_input_get_buttons_fn(device_get_buttons);
   634→            set_input_wait_button_fn(device_wait_button);
   635→            set_fs_opendir_fn(device_opendir);
   636→            set_fs_readdir_fn(device_readdir);
   637→            set_fs_closedir_fn(device_closedir);
   638→            INPUT_PTR = input_ref as *mut _;
   639→        }
